SELECT id_order, id_user, qt_order_amount, nm_order_person, nm_delivery_address, da_order, st_order FROM tb_order
AND id_user LIKE '%' || #{idUser} || '%'
AND TO_CHAR(da_order, 'YYYY-MM-DD') = #{daOrderDate}
AND st_order = #{stOrder}
ORDER BY da_order DESC, id_order DESC OFFSET (#{page} * #{size}) ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*)
FROM tb_order


        AND id_user LIKE '%' || #{idUser} || '%'


        AND TO_CHAR(da_order, 'YYYY-MM-DD') = #{daOrderDate}


        AND st_order = #{stOrder}
